package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElementVerwerker;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.UitzPerUurModus;
import be.schaubroeck.lpb.rkm.rekenmotor.util.AantalKalenderDagen;
import be.schaubroeck.lpb.rkm.rekenmotor.util.AantalRszDagen;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PrestatieSamenvatting;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.WeddeBerekening;
import be.schaubroeck.lpb.tools.enumtypes.Maandverwerking;
import be.schaubroeck.lpb.tools.enumtypes.RekenControleCode;

import java.math.BigDecimal;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONCODE_GEWOON_LOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.UITZONDERLIJK_PER_UUR_KEY;

public class VerwerkPrestaties {

    private static final String WAARSCHUWING_NOEMER_PLANNINGSUREN_ZERO = "planningsuren met noemer 0 herleid naar dertigsten";

    private final Disponibiliteit disponibiliteit;
    private final PrestatiesGewoneBezoldiging prestatiesGewoneBezoldiging;
    private final PrestatiesDisponibiliteit prestatiesDisponibiliteit;
    private final PrestatiesEuropeseVakantie prestatiesEuropeseVakantie;
    private final PrestatiesZiekte prestatiesZiekte;
    private final PrestatiesGewaarborgdLoon100PctOfDispo prestatiesGewaarborgdLoon100PctOfDispo;
    private final PrestatiesDeeltijdseWerkhervatting prestatiesDeeltijdseWerkhervatting;

    public VerwerkPrestaties(ConstantManager constantManager, LoonElementVerwerker loonElementVerwerker) {
        this.disponibiliteit = new Disponibiliteit(constantManager);
        this.prestatiesGewoneBezoldiging = new PrestatiesGewoneBezoldiging(constantManager, loonElementVerwerker, disponibiliteit);
        this.prestatiesDisponibiliteit = new PrestatiesDisponibiliteit(loonElementVerwerker, disponibiliteit);
        this.prestatiesEuropeseVakantie = new PrestatiesEuropeseVakantie(constantManager, loonElementVerwerker);
        this.prestatiesZiekte = new PrestatiesZiekte(constantManager, loonElementVerwerker);
        this.prestatiesGewaarborgdLoon100PctOfDispo = new PrestatiesGewaarborgdLoon100PctOfDispo(loonElementVerwerker);
        this.prestatiesDeeltijdseWerkhervatting =
                new PrestatiesDeeltijdseWerkhervatting(loonElementVerwerker, prestatiesDisponibiliteit, disponibiliteit);
    }

    public void verwerk(RekenContext context, SleutelGegevens aggregaat, MoneyMap<AardKodeExtensie> carryoverMap) {
        for (Opper opper : aggregaat.getOppers()) {
            verwerk(context, opper, carryoverMap);
        }
    }

    private void verwerk(RekenContext context, Opper opper, MoneyMap<AardKodeExtensie> carryoverMap) {
        LoonElementManager manager = context.getLoonElementManager();
        LoonCodeManager loonCodeManager = context.getLoonCodeManager();
        RekenTijd rekenTijd = context.getRekenTijd();
        AardKodeExtensie looncodeGewoonLoon = context.getUnchecked(LOONCODE_GEWOON_LOON_KEY);

        PrestatieSamenvatting samenvatting = context.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_KEY, opper);
        BigDecimal prestatieNoemer = getPrestatieNoemer(opper, rekenTijd, samenvatting);
        UitzPerUurModus uitzPerUurModus = context.getUnchecked(UITZONDERLIJK_PER_UUR_KEY);
        if (uitzPerUurModus != null && uitzPerUurModus != UitzPerUurModus.GEEN) {
            PrestatieSamenvatting samenvattingPerUur = context.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_UIT_PER_UUR_KEY, opper);
            // todo hier voor de volgende fase
            BigDecimal prestatieNoemerPerUur = samenvattingPerUur.getTotaalAantalUren();
            if (prestatieNoemerPerUur.signum() != 0) {
                samenvatting = samenvattingPerUur;
                prestatieNoemer = prestatieNoemerPerUur;
            } else {
                RegulManager regulManager = context.getRegulManager();
                regulManager.addProtoWaarschuwing(opper.getOpdracht(), RekenControleCode.PLANNINGSUREN_NOEMER_ZERO, WAARSCHUWING_NOEMER_PLANNINGSUREN_ZERO);
            }
        }

        if (prestatieNoemer.signum() != 0) {
            prestatiesGewoneBezoldiging.verwerk(manager, loonCodeManager, rekenTijd, looncodeGewoonLoon, samenvatting, prestatieNoemer, opper,
                    carryoverMap);
            prestatiesEuropeseVakantie.verwerk(manager, loonCodeManager, rekenTijd, samenvatting, prestatieNoemer, opper, carryoverMap);
            prestatiesZiekte.verwerk(manager, loonCodeManager, rekenTijd, looncodeGewoonLoon, samenvatting, prestatieNoemer, opper, carryoverMap);
            prestatiesGewaarborgdLoon100PctOfDispo.verwerk(manager, rekenTijd, samenvatting, prestatieNoemer, opper, carryoverMap);
            prestatiesDisponibiliteit.verwerk(manager, loonCodeManager, rekenTijd, looncodeGewoonLoon, samenvatting, prestatieNoemer, opper, carryoverMap);
            prestatiesDeeltijdseWerkhervatting.verwerk(manager, loonCodeManager, rekenTijd, looncodeGewoonLoon, samenvatting, prestatieNoemer, opper, carryoverMap);
        }
    }

    private BigDecimal getPrestatieNoemer(Opper opper, RekenTijd rekenTijd, PrestatieSamenvatting samenvatting) {
        WeddeBerekening weddeBerekening = opper.getWeddeBerekening();
        Maandverwerking maandNaarDag = weddeBerekening.getOmzettingLoonMaandNaarDag();
        switch (maandNaarDag) {
            case DERTIGSTEN:
            case PLANNINGSUREN:
                return new BigDecimal("30");
            case RSZDAGEN:
                return AantalRszDagen.inMaand(opper, rekenTijd.rekenPeriode);
            case KALENDERDAGEN:
                return AantalKalenderDagen.inMaand(rekenTijd.rekenPeriode);
            case VARIABELE_RSZ_DAGEN:
            case VLAAMSE_GEMEENSCHAP:
                return samenvatting.getWerkDagen();
            default:
                return BigDecimal.ONE;
        }
    }
}
